parameters.inputSchema:
{
  "type": "object",
  "additionalProperties": false,
  "required": ["script", "music_prompt", "scenes"],
  "properties": {
    "script": {
      "type": "string",
      "description": "One continuous voiceover script (no labels, no bullets)."
    },
    "music_prompt": {
      "type": "string",
      "description": "Deterministic music prompt string built from music_analysis fields."
    },
    "scenes": {
      "type": "array",
      "minItems": 1,
      "description": "One output scene per input scene, in the same order.",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": ["scene", "start_image_prompt", "video_prompt"],
        "properties": {
          "scene": {
            "type": "string",
            "description": "Format: 'Scene X - Title' (Title is 2–4 words)."
          },
          "start_image_prompt": {
            "type": "string",
            "description": "Single string. If reference images exist, first line must be the required sentence. Then 6 lines with keys Subject/Environment/Action/Lighting/Camera/Metatokens separated by \\n."
          },
          "video_prompt": {
            "type": "string",
            "description": "Single string with 6 lines: Subject/Environment/Action/Lighting/Camera/Metatokens separated by \\n."
          }
        }
      }
    }
  }
}

