parameters.jsCode:
// Sort records by scene title to ensure correct order
const records = $input.all();

// Create consecutive image pairs
const pairs = [];

for (let i = 0; i < records.length; i++) {
  const currentRecord = records[i].json;
  const nextRecord = i < records.length - 1 ? records[i + 1].json : null;

  pairs.push({
    json: {
      recordId: currentRecord.id,
      currentImage: currentRecord.start_image && currentRecord.start_image[0] ? currentRecord.start_image[0].url : null,
      nextImage: nextRecord && nextRecord.start_image && nextRecord.start_image[0] ? nextRecord.start_image[0].url : null,
      video_prompt: currentRecord.video_prompt
    }
  });
}

return pairs;

// Collect all Airtable attachment URLs from the field "video_scene"
const urls = [];

for (const item of $input.all()) {
  const att = item.json.video_scene; // Airtable attachment field
  if (Array.isArray(att) && att[0]?.url) {
    urls.push(att[0].url);
  }
}

// Output as a single item with video_urls array
return [
  {
    json: {
      video_urls: urls
    }
  }
];
